\begin{definition}[Observer-Induced Metric]\label{definition:bk4_observer_metric}
Let $(M, g)$ be a smooth Riemannian manifold of dimension $n$ on the Book I symbolic manifold substrate (Def.~\ref{definition:bk1_symbolic_manifold}) and let $O$ be a Bounded Observer (Def.~\ref{definition:bk1_bounded_observer}) with resolution kernel $K_O: TM \to TM$ satisfying the following conditions:
\begin{enumerate}
    \item $K_O$ is a smoothing operator with characteristic scale $\epsilon_O > 0$
    \item $K_O$ preserves the fiber structure: $K_O(T_pM) \subseteq T_pM$ for all $p \in M$
    \item $K_O$ is self-adjoint with respect to the base metric $g$
\end{enumerate}
The \textbf{observer-induced metric} $g_O$ on the tangent bundle $TM$ is defined as the perceived metric tensor field given by:
\begin{equation}
    g_O(p)(v, w) := \langle K_O v, K_O w \rangle_{g(p)}
\end{equation}
where $v, w \in T_pM$ and $\langle \cdot, \cdot \rangle_{g(p)}$ denotes the inner product induced by $g$ at point $p$.
\end{definition}

\begin{lemma}[Properties of Observer-Induced Metric]\label{lemma:bk4_observer_metric_properties}
The observer-induced metric $g_O$ from Def.~\ref{definition:bk4_observer_metric} satisfies:
\begin{enumerate}
    \item \textbf{Positivity}: $g_O(p)(v,v) \geq 0$ with equality if and only if $K_O v = 0$
    \item \textbf{Symmetry}: $g_O(p)(v,w) = g_O(p)(w,v)$ for all $v,w \in T_pM$
    \item \textbf{Scale Invariance}: If $K_O$ has characteristic scale $\epsilon_O$, then $g_O$ exhibits scaling behavior under coordinate transformations with scale factor $\lambda$: $g_O^{(\lambda)} = \lambda^{-2} g_O$
\end{enumerate}
\end{lemma}

\begin{proof}[Observer Metric Properties]
\label{proof:bk4_observer_metric_properties}
\leavevmode

Properties (1) and (2) follow from the self-adjointness of $K_O$ and positive-definiteness of $g$.
For (3), under a scaling $x \mapsto \lambda x$, the kernel transforms as $K_O^{(\lambda)} = \lambda^{-1} K_O$, yielding the stated scaling behavior.
\end{proof}

