\begin{theorem}[Observer-Relative Chain Rule]
\label{theorem:bk4_fuzzy_chain_rule}
Let $\tilde{\mathcal{M}}_1, \tilde{\mathcal{M}}_2, \tilde{\mathcal{M}}_3$ be observer-induced fuzzy membranes relative to Bounded Observer $\mathcal{O}$ (Def.~\ref{definition:bk1_bounded_observer}). Let $g: \tilde{\mathcal{M}}_1 \rightarrow \tilde{\mathcal{M}}_2$ be $\mathcal{O}$-differentiable at $p$, and $f: \tilde{\mathcal{M}}_2 \rightarrow \tilde{\mathcal{M}}_3$ be $\mathcal{O}$-differentiable at $g(p)$ in the observer-valid sense of Def.~\ref{definition:bk4_observer_valid_different}. Then the composition $h = f \circ g$ is $\mathcal{O}$-differentiable at $p$, and its $\mathcal{O}$-derivative is:
\begin{align}
\mathcal{L}_h(p) = \mathcal{L}_f(g(p)) \circ \mathcal{L}_g(p)
\end{align}
where the compositional error is bounded by:
\begin{align}
\|\delta^1_{\mathcal{O}}(\mathcal{E}_{\text{total}})\| \leq \|\delta^1_{\mathcal{O}}(\mathcal{L}_f(\mathcal{E}_g))\| + \|\delta^1_{\mathcal{O}}(\mathcal{E}_f)\| < t \cdot \varepsilon_{\mathcal{O}}(p)
\end{align}

\textbf{Cross-Field Realizations of Compositional Error Propagation:}

\begin{itemize}
