\end{theorem}

\begin{proof}[$\mathcal{O}$-Bounded Error Propagation in Chain Rule]
\label{proof:bk4_sketch_sub_thresholds}
\leavevmode

The proof carries observer-bounded error terms through composition.
It invokes Thm.~\ref{theorem:bk4_fuzzy_chain_rule}.
It also uses observer-valid differentiability.
Cf.~Def.~\ref{definition:bk4_observer_valid_different}:

\textbf{Step 1: Expand Composition}
\begin{align}
h(p + tv) = f(g(p + tv))
\end{align}

\textbf{Step 2: Apply $\mathcal{O}$-differentiability of $g$}
\begin{align}
g(p + tv) = g(p) + t\mathcal{L}_g(v) + \mathcal{E}_g
\end{align}
where $\|\delta^1_{\mathcal{O}}(\mathcal{E}_g)\| < t \cdot \varepsilon_{\mathcal{O}}(p)$

\textbf{Step 3: Apply $\mathcal{O}$-differentiability of $f$}
\begin{align}
f(g(p) + t\mathcal{L}_g(v) + \mathcal{E}_g) = f(g(p)) + \mathcal{L}_f(t\mathcal{L}_g(v) + \mathcal{E}_g) + \mathcal{E}_f
\end{align}

\textbf{Step 4: Bound the Total Error}
\begin{align}
\mathcal{E}_{\text{total}} = \mathcal{L}_f(\mathcal{E}_g) + \mathcal{E}_f
\end{align}
Since $f$ is $\mathcal{O}$-differentiable, $\mathcal{L}_f$ is $\mathcal{O}$-bounded: there exists a finite observer-frame operator norm $\|\mathcal{L}_f\|_{\mathcal{O}} < \infty$ such that $\|\mathcal{L}_f(w)\| \leq \|\mathcal{L}_f\|_{\mathcal{O}} \cdot \|w\|$ for all $w$. Applying this to $\mathcal{E}_g$:
\begin{align}
\|\delta^1_{\mathcal{O}}(\mathcal{L}_f(\mathcal{E}_g))\| \leq \|\mathcal{L}_f\|_{\mathcal{O}} \cdot \|\delta^1_{\mathcal{O}}(\mathcal{E}_g)\| < \|\mathcal{L}_f\|_{\mathcal{O}} \cdot t \cdot \varepsilon_{\mathcal{O}}(p).
\end{align}
For $\mathcal{E}_f$: the $\mathcal{O}$-differentiability of $f$ at the perturbed input $g(p) + t\mathcal{L}_g(v)$ gives $\|\delta^1_{\mathcal{O}}(\mathcal{E}_f)\| < t' \cdot \varepsilon_{\mathcal{O}}(g(p))$ where $t' \leq t(\|\mathcal{L}_g\|_{\mathcal{O}} + \varepsilon_{\mathcal{O}}(p))$. Since $g$ is $\mathcal{O}$-compatible, $\varepsilon_{\mathcal{O}}(g(p)) \leq C_g \cdot \varepsilon_{\mathcal{O}}(p)$ for an observer-scale constant $C_g$. Therefore:
\begin{align}
\|\delta^1_{\mathcal{O}}(\mathcal{E}_{\text{total}})\|
&< t \bigl(\|\mathcal{L}_f\|_{\mathcal{O}}
+ C_g(\|\mathcal{L}_g\|_{\mathcal{O}} + \varepsilon_{\mathcal{O}}(p))\bigr)
\cdot \varepsilon_{\mathcal{O}}(p).
\end{align}
The parenthesized coefficient is finite (both operator norms are
$\mathcal{O}$-finite by assumption). Hence:
\[
\|\delta^1_{\mathcal{O}}(\mathcal{E}_{\text{total}})\|
< C_{\text{chain}} \cdot t \cdot \varepsilon_{\mathcal{O}}(p)
\]
for an observer-scale constant $C_{\text{chain}}$. The total error is therefore
sub-threshold, completing the proof.
\end{proof}

