\begin{proof}[Power Rule via Binomial Expansion and Recursive Error Bound]
\label{proof:bk4_sketch_extracting_recrusive_curvature}
\leavevmode

This proof provides the explicit expansion argument for
Thm.~\ref{theorem:bk4_fuzzy_power_rule}.
It reuses the Book IV cross-error curvature mechanism from
Thm.~\ref{theorem:bk4_multiplication_to_curvature} under Book I observer
bounds (Def.~\ref{definition:bk1_bounded_observer}).
The proof demonstrates how symbolic self-interaction creates geometric curvature through recursive feedback in observer-bounded systems:

\textbf{Step 1: Expand Power Differential}
\begin{align}
h(p + tv) = [f(p + tv)]^n
\end{align}

\textbf{Step 2: Apply $\mathcal{O}$-differentiability of $f$}
\begin{align}
f(p + tv) = f(p) + t\mathcal{L}_f(v) + \mathcal{E}_f
\end{align}
where $\|\delta^1_{\mathcal{O}}(\mathcal{E}_f)\| < t \cdot \varepsilon_{\mathcal{O}}(p)$

\textbf{Step 3: Binomial Expansion with Observer-Bounded Terms}
\begin{align}
h(p + tv) = [f(p) + t\mathcal{L}_f(v) + \mathcal{E}_f]^n
\end{align}
\begin{align}
= f^n(p) + n f^{n-1}(p) \cdot t\mathcal{L}_f(v) + \frac{n(n-1)}{2} f^{n-2}(p) \cdot t^2\|\mathcal{L}_f(v)\|^2 + \text{h.o.t.}
\end{align}

\textbf{Step 4: Bound the Power Error and Identify Recursive Curvature}

From Step 3, the total error after extracting the first-order term $n f^{n-1}(p)\cdot t\mathcal{L}_f(v)$ is:
\begin{align}
\mathcal{E}_{\text{total}} = \frac{n(n-1)}{2}f^{n-2}(p)(t\mathcal{L}_f(v))^2 + \sum_{k=1}^{n}\binom{n}{k}f^{n-k}(p)\mathcal{E}_f^k + \text{h.o.t.}
\end{align}
The leading quadratic term: $\|\frac{n(n-1)}{2}f^{n-2}(p)(t\mathcal{L}_f)^2\| = O(t^2)$, so $\|\delta^1_{\mathcal{O}}(\cdot)\|/t \leq \frac{n(n-1)}{2}\|f\|^{n-2}\|\mathcal{L}_f\|^2 \cdot t \to 0$ as $t \to 0$. This is the $\mathcal{O}$-visible curvature contribution $\Delta_{\mathcal{O}}(n,f)$, sub-threshold for finite $t < \varepsilon_{\mathcal{O}}(p)/\|\mathcal{L}_f\|^2$.

For the cross-terms with $\mathcal{E}_f$: since $\|\delta^1_{\mathcal{O}}(\mathcal{E}_f)\| < t\varepsilon_{\mathcal{O}}(p)$, each mixed term of order $k\geq 1$ satisfies:
\begin{align}
\left\|\binom{n}{k}f^{n-k}(p)\mathcal{E}_f^k\right\| \leq \binom{n}{k}\|f\|^{n-k}(t\varepsilon_{\mathcal{O}}(p))^k.
\end{align}
Summing over $k=1,\ldots,n$ and dividing by $t$: each term is bounded by $\binom{n}{k}\|f\|^{n-k}t^{k-1}\varepsilon_{\mathcal{O}}^k(p)$, which for $k\geq 1$ is at most $C(n,f)\varepsilon_{\mathcal{O}}(p)$ for $t \leq 1$. Hence $\|\delta^1_{\mathcal{O}}(\mathcal{E}_{\text{total}})\| < C_{\text{pow}}\,t\,\varepsilon_{\mathcal{O}}(p)$ for a finite observer-scale constant $C_{\text{pow}}$, completing the proof.
\end{proof}

